        if (entries.length === 0) {
          return {
            content: [
              {
                type: "text",
                text: JSON.stringify({
                  analyzed: true,
                  candidates: [],
                  message: "No memories found to analyze."
                })
              }
            ]
          };
        }
        const memorySummaries = entries.map((e) => ({
          id: e.id,
          title: e.title,
          type: e.type,
          tags: e.tags,
          createdAt: e.createdAt,
          updatedAt: e.updatedAt,
          preview: e.content.slice(0, 300),
          scope: e._scope
        }));
