// src/mcp/coworker/actions.ts
async function handleCoworkerAction(action, args, ctx) {
  const projectRoot = ctx.getProjectRoot() ?? process.cwd();
  switch (action) {
    case "send":
      return handleCoworkerSend(args, projectRoot);
    case "review":
      return handleCoworkerReview(args, projectRoot);
    case "diff":
      return handleCoworkerDiff(args, projectRoot);
    case "fork":
      return handleCoworkerFork(args, projectRoot);
    case "approve":
      return handleCoworkerApprove(args, projectRoot);
    case "revert":
      return handleCoworkerRevert(args, projectRoot);
    case "status":
      return handleCoworkerStatus(projectRoot);
    case "recent_activity":
      return handleCoworkerRecentActivity(args, projectRoot);
  }
}
function parseCoworkerTaskAction(action) {
  const normalized = normalizeCoworkerTaskAction(String(action ?? "").trim());
  if (!normalized) {
    throw new Error(`Unsupported coworker action: ${String(action ?? "")}`);
  }
  return normalized;
}

// src/mcp/coworker/index.ts
async function handleCoworkerTool(name, args, ctx) {
  if (name !== "coworker_task") {
    return;
  }
  try {
    const action = parseCoworkerTaskAction(args.action);
    const nextArgs = { ...args };
    delete nextArgs.action;
    return await handleCoworkerAction(action, nextArgs, ctx);
  } catch (error2) {
    return errorResult(String(args.target ?? "coworker"), error2);
  }
}

